import React, { useEffect, useState } from "react";
import axios from "axios";
import {
  BarChart,
  Bar,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  Legend,
  ResponsiveContainer,
} from "recharts";

const API_URL = "http://localhost:7000/api/prices/trends";

export default function PriceAnalytics() {
  const [type, setType] = useState("product");
  const [range, setRange] = useState("monthly");
  const [filter, setFilter] = useState("");
  const [data, setData] = useState([]);
  const [filterOptions, setFilterOptions] = useState([]);

  // 🔹 Fetch trends from backend
  const fetchTrends = async () => {
    try {
      const res = await axios.get(API_URL, {
        params: { type, range, filter },
      });
      setData(Array.isArray(res.data) ? res.data : []);
    } catch (err) {
      console.error("Error fetching trends:", err);
    }
  };

  // 🔹 Load filter options from all prices
  const fetchFilters = async () => {
    try {
      const res = await axios.get("http://localhost:7000/api/prices");
      if (Array.isArray(res.data)) {
        const options =
          type === "category"
            ? [...new Set(res.data.map((i) => i.category).filter(Boolean))]
            : [...new Set(res.data.map((i) => i.name).filter(Boolean))];
        setFilterOptions(options);
      }
    } catch (err) {
      console.error("Error loading filter options:", err);
    }
  };

  useEffect(() => {
    fetchTrends();
    fetchFilters();
  }, [type, range, filter]);

  // 🔹 Handle empty or invalid data
  const productList = Array.isArray(data) ? data : [];

  return (
    <div className="p-6 bg-gray-50 min-h-screen">
      <h1 className="text-2xl font-bold mb-4">📊 Price Analytics Dashboard</h1>

      <div className="flex flex-wrap gap-4 mb-6">
        <select
          className="border p-2 rounded"
          value={type}
          onChange={(e) => setType(e.target.value)}
        >
          <option value="product">Product Wise</option>
          <option value="category">Category Wise</option>
        </select>

        <select
          className="border p-2 rounded"
          value={range}
          onChange={(e) => setRange(e.target.value)}
        >
          <option value="weekly">Last 30 Days (Weekly)</option>
          <option value="monthly">Last 6 Months (Monthly)</option>
        </select>

        <select
          className="border p-2 rounded"
          value={filter}
          onChange={(e) => setFilter(e.target.value)}
        >
          <option value="">All</option>
          {filterOptions.map((opt) => (
            <option key={opt} value={opt}>
              {opt}
            </option>
          ))}
        </select>

        <button
          className="bg-blue-600 text-white px-4 py-2 rounded"
          onClick={fetchTrends}
        >
          Refresh Data
        </button>
      </div>

      {productList.length === 0 ? (
        <p className="text-gray-600">No data found for the selected filters.</p>
      ) : (
        productList.map((item) => (
          <div
            key={item._id}
            className="bg-white p-4 rounded-xl shadow mb-6 border"
          >
            <h2 className="text-xl font-semibold mb-2 text-blue-700">
              {type === "category" ? "Category" : "Product"}: {item._id}
            </h2>

            <ResponsiveContainer width="100%" height={300}>
              <BarChart data={item.prices}>
                <CartesianGrid strokeDasharray="3 3" />
                <XAxis dataKey="date" />
                <YAxis />
                <Tooltip />
                <Legend />
                <Bar dataKey="avgPrice" name="Average Price" fill="#4F46E5" />
                <Bar
                  dataKey="difference"
                  name="Price Change"
                  fill="#10B981"
                />
              </BarChart>
            </ResponsiveContainer>
          </div>
        ))
      )}
    </div>
  );
}
